import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils; // Import from Apache Commons Text library
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String safeUserInput = StringEscapeUtils.escapeHtml4(userInput); // Sanitize user input

        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>Secure Servlet Example</title></head>");
        out.println("<body>");
        out.println("<h1>User Input: " + safeUserInput + "</h1>"); // Safe output of sanitized user input
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
